 .../java/io/crate/auth/AccessControlImpl.java | 112 ++++++++----------
 .../io/crate/metadata/table/ShardedTable.java |   3 +
 .../auth/AccessControlMayExecuteTest.java     |  12 ++
 4 files changed, 67 insertions(+), 64 deletions(-)

